const NAV_GROUPS=[
  {label:'Học hôm nay',items:[['dashboard','Learning Console','⌘','dashboard.html'],['lesson','Run Lesson','▶','lesson.html'],['practice','Skill Practice','⚡','practice.html'],['homework','Homework','📚','homework.html'],['essays','Essay Workspace','📝','essays.html']]},
  {label:'Ôn tập',items:[['review-queue','Review Queue','🔁','review-queue.html'],['error-book','Error Log','🐞','error-book.html'],['band-tracker','Band Tracker','📈','band-tracker.html'],['course-qa','Course QA','⭐','course-qa.html']]},
  {label:'Kho học liệu',items:[['roadmap','Roadmap','🗺️','roadmap.html'],['prompt-bank','Prompt Bank','🧠','prompt-bank.html'],['exercise-bank','Exercise Bank','🧪','exercise-bank.html'],['sample-database','Samples','🏆','sample-database.html'],['resource-library','Resource Library','📦','resource-library.html'],['vocabulary','Vocabulary','💬','vocabulary.html'],['idea-bank','Idea Bank','💡','idea-bank.html'],['chapter-review','Chapter Review','🧭','chapter-review.html']]},
  {label:'AI Tutor & Account',items:[['ai-context-builder','Ask Chị Builder','🤖','ai-context-builder.html'],['feedback','Feedback','🧾','feedback.html'],['teacher-notes','Teacher Notes','🗒️','teacher-notes.html'],['profile-backup','Profile & Backup','🧰','profile-backup.html'],['changelog','Changelog','🚀','changelog.html'],['login','Switch Account','🔐','login.html']]}
];
const TEACHER_ITEMS=[['teacher-dashboard','Teacher Dashboard','🧑‍🏫','teacher-dashboard.html'],['teacher-mode','Teacher Mode','👩‍🏫','teacher-mode.html'],['custom-assignment','Custom Assignment','🧩','custom-assignment.html']];
const ADMIN_ITEMS=[['admin-dashboard','Admin Dashboard','🛡️','admin-dashboard.html'],['user-management','User Management','👥','user-management.html'],['course-builder','Course Builder','🏗️','course-builder.html']];
function arr(x){return Array.isArray(x)?x:[]}
function obj(x){return x&&typeof x==='object'&&!Array.isArray(x)?x:{}}
function esc(x){return (window.UI&&UI.esc?UI.esc(x):String(x??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])))}
function attr(x){return (window.UI&&UI.attr?UI.attr(x):esc(x))}
function pct(a,b){return Math.max(0,Math.min(100,Math.round((Number(a)||0)/(Number(b)||1)*100)))}
function wc(t){return (String(t||'').trim().match(/\b[\w'-]+\b/g)||[]).length}
function toast(msg){if(window.UI&&UI.toast)UI.toast(msg);else alert(msg)}
function uid(p='id'){return (window.Store&&Store.uid?Store.uid(p):p+'-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,7))}
function today(){return (window.Store&&Store.today?Store.today():new Date().toISOString().slice(0,10))}
function addDays(n){if(window.Store&&Store.addDays)return Store.addDays(n);const d=new Date();d.setDate(d.getDate()+Number(n||0));return d.toISOString().slice(0,10)}
function data(){const D=window.IELTS_DATA||{};return {lessons:arr(D.lessons),chapters:arr(D.chapters),prompts:arr(D.prompts),exercises:arr(D.exerciseBank||D.practiceExercises),ideas:arr(D.ideaBank||D.ideas),vocab:arr(D.vocabulary),samples:arr(D.sampleDatabase||D.sampleEssays),resources:arr(D.lessonResources),reviews:arr(D.chapterReviews),topics:arr(D.topics).length?arr(D.topics):unique(arr(D.prompts).map(p=>p.topic).filter(Boolean)),types:arr(D.essayTypes).length?arr(D.essayTypes):unique(arr(D.prompts).map(p=>p.essayType||p.type).filter(Boolean)),badges:arr(D.badges)}}
function unique(a){return [...new Set(a.filter(Boolean))]}
function load(){try{return window.Store&&Store.load?Store.load():{studentProfile:{name:'Phúc',currentBand:5.5,targetBand:6.5,expectedExamDate:addDays(90),dailyGoal:{lessons:1,minutes:45,exercises:5}},settings:{theme:'dark'},lessonStatus:{},homework:{},essays:[],errors:[],reviewQueue:[],teacherNotes:[],bandHistory:[],studySessions:[],exerciseAnswers:{},promptStatus:{},xp:0,streak:{count:0}}}catch(e){return {studentProfile:{name:'Phúc',currentBand:5.5,targetBand:6.5,expectedExamDate:addDays(90)},settings:{theme:'dark'},lessonStatus:{}}}}
function saveUpdate(fn){if(window.Store&&Store.update)return Store.update(fn);return fn(load())}
function user(){try{return window.Accounts&&Accounts.currentUser?Accounts.currentUser():{id:'phuc',name:'Phúc',role:'student',username:'phuc',pin:'1234',avatar:'PH'}}catch(e){return {id:'phuc',name:'Phúc',role:'student',username:'phuc',pin:'1234',avatar:'PH'}}}
function role(){return user().role||'student'}
function pageDir(){return /(?:^|\/)pages(?:\/|$)/.test(location.pathname)}
function href(file){return pageDir()?file:'pages/'+file}
function res(path){if(!path)return '#';return pageDir()?'../'+path:path}
function pageFromUrl(){const f=(location.pathname.split('/').pop()||'dashboard.html').replace(/\.html$/,'');if(!f||f==='index')return 'dashboard';return PAGE_META[f]?f:(document.body.dataset.page||'dashboard')}
function title(t,s){const h=document.getElementById('pageTitle'), sub=document.getElementById('pageSub');if(h)h.textContent=t;if(sub)sub.textContent=s||'';document.title=(t||'IELTS Academy')+' · IELTS Academy v7.0'}
function currentStatus(id,d=load()){const st=obj(d.lessonStatus)[id];if(st)return st;if(obj(d.completedLessons)[id])return 'mastered';const l=lessonById(id);if(!l)return 'learn';const D=data();const prev=D.lessons[D.lessons.findIndex(x=>x.id===id)-1];if(prev&&currentStatus(prev.id,d)!=='mastered'&&Number(l.chapterNo)>1)return 'locked';return 'learn'}
function setStatus(id,st){saveUpdate(d=>{d.lessonStatus=d.lessonStatus||{};d.lessonStatus[id]=st;if(st==='mastered'){d.completedLessons=d.completedLessons||{};d.completedLessons[id]=true}return d})}
function lessonById(id){return data().lessons.find(l=>l.id===id)||data().lessons[0]||{id:'lesson-1',title:'Lesson',skill:'orientation',chapterNo:1,lessonNo:1}}
function nextLesson(d=load()){return data().lessons.find(l=>!['mastered','locked'].includes(currentStatus(l.id,d)))||data().lessons.find(l=>currentStatus(l.id,d)==='locked')||data().lessons[0]||lessonById()}
function selectedLesson(){const id=new URLSearchParams(location.search).get('lesson')||load().currentLessonId;return lessonById(id)||nextLesson()}
function dateDiff(date){if(!date)return null;return Math.ceil((new Date(date+'T23:59:59')-new Date())/86400000)}
function compact(t,n=150){t=String(t||'');return t.length>n?t.slice(0,n)+'…':t}
function statusPill(s){return `<span class="pill status-${esc(s)}">${esc(s)}</span>`}
function flowLine(st){const flow=['learn','practice','homework','reviewed','rewrite','mastered'];return `<div class="flow-line">${flow.map(x=>`<span class="flow-step ${x===st?'active':''} ${flow.indexOf(x)<flow.indexOf(st)?'done':''}">${x}</span>`).join('')}</div>`}
function progress(d=load()){const D=data(), total=D.lessons.length||1, m=D.lessons.filter(l=>currentStatus(l.id,d)==='mastered').length;return pct(m,total)}
function roleItems(){let gs=NAV_GROUPS.map(g=>({...g,items:g.items.slice()}));if(role()==='teacher'||role()==='admin')gs.push({label:'Teacher',items:TEACHER_ITEMS});if(role()==='admin')gs.push({label:'Admin',items:ADMIN_ITEMS});return gs}
function navItem(item,page){return `<a class="nav-link ${item[0]===page?'active':''}" href="${href(item[3])}" data-route="${item[0]}" data-file="${item[3]}"><span class="nav-ico">${item[2]}</span><span>${item[1]}</span></a>`}
function layout(page){const d=load(), u=user(), p=d.studentProfile||{};const theme=(d.settings&&d.settings.theme)||'dark', stylePreset=(d.settings&&d.settings.stylePreset)||'code';document.documentElement.dataset.theme=theme;document.body.dataset.theme=theme;document.documentElement.dataset.style=stylePreset;document.body.dataset.style=stylePreset;document.body.dataset.page=page;const app=document.getElementById('app');if(!app)return;app.innerHTML=`<div class="v5-shell v7-shell"><aside class="sidebar v5-sidebar v7-sidebar"><div class="brand v5-brand v7-brand"><div class="brand-logo">AI</div><div><h1>IELTS Academy <span>v7.0</span></h1><p>Ask Chị Context Engine</p></div></div><div class="profile-mini"><div class="avatar">${esc((u.avatar||p.name||'IA').slice(0,2).toUpperCase())}</div><div><b>${esc(p.name||u.name||'Phúc')}</b><p><span class="role-badge role-${esc(u.role||'student')}">${esc(u.role||'student')}</span> · Band ${esc(p.currentBand||5.5)} → ${esc(p.targetBand||6.5)}</p></div></div><a class="big-run" href="${href('lesson.html')}" data-route="lesson" data-file="lesson.html">▶ Run Today’s Lesson</a>${roleItems().map(g=>`<div class="nav-section">${esc(g.label)}</div>${g.items.map(i=>navItem(i,page)).join('')}`).join('')}<div class="sidebar-mini"><strong>Context pipeline</strong><p>Do task → Auto-capture → Ask Chị → Rewrite.</p><div class="progress animated"><span style="width:${progress(d)}%"></span></div><p>${progress(d)}% · ${Number(d.xp||0)} XP · ${Number((d.streak||{}).count||0)} streak</p></div></aside><main class="main v5-main v7-main"><div class="topbar v5-top v7-top"><div><h2 id="pageTitle"></h2><p id="pageSub"></p></div><div class="top-actions"><input class="search" id="globalSearch" placeholder="Search lessons, prompts, errors..."/><button class="btn ask-teacher glow" id="askTop">💬 Ask Chị</button><button class="btn ghost" id="themeBtn">${theme==='light'?'☀️':'🌙'} Theme</button><button class="btn ghost" id="styleBtn">🎨 ${esc(stylePreset)}</button></div></div><div id="view" class="page-transition"></div><div class="footer-note">IELTS Academy v7.0 online/static demo. Ask Chị prompt tự gom dữ liệu đang học từ localStorage. PIN chỉ là mô phỏng, không phải bảo mật thật.</div></main></div>`;document.getElementById('themeBtn').onclick=()=>{saveUpdate(x=>{x.settings=x.settings||{};x.settings.theme=(x.settings.theme==='light')?'dark':'light';return x});renderPage(page)};document.getElementById('styleBtn').onclick=()=>showStyleModal(page);document.getElementById('globalSearch').addEventListener('keydown',e=>{if(e.key==='Enter'){navigate('prompt-bank','prompt-bank.html?q='+encodeURIComponent(e.target.value.trim()))}});document.getElementById('askTop').onclick=()=>askTeacher({source:page,taskType:'Quick question',problem:'Em muốn hỏi nhanh về trang hiện tại.'},'Quick');document.querySelectorAll('a[data-route]').forEach(a=>a.addEventListener('click',e=>{if(e.button||e.ctrlKey||e.metaKey||e.shiftKey||e.altKey)return;e.preventDefault();navigate(a.dataset.route,a.getAttribute('href'))}))}
function showStyleModal(page){const d=load(), current=(d.settings&&d.settings.stylePreset)||'code';const packs=['code','anime','minecraft','ocean','minimal','neon','galaxy','candy','forest','academic'];const names={code:'Lập trình code',anime:'Anime pastel',minecraft:'Minecraft grass/craft',ocean:'Blue ocean focus',minimal:'Sáng tối giản',neon:'Neon AI dashboard',galaxy:'Galaxy AI',candy:'Anime Candy',forest:'Forest Focus',academic:'IELTS Center Clean'};const m=UI.modal('Chọn style giao diện',`<p class="muted">Style chỉ đổi cảm giác học, không làm mất dữ liệu.</p><div class="style-grid">${packs.map(x=>`<button class="style-card ${x===current?'active':''}" data-style-choice="${x}"><span class="style-preview style-${x}"></span><b>${names[x]}</b><small>${x}</small></button>`).join('')}</div>`,`<button class="btn" data-close-style>Đóng</button>`);m.querySelectorAll('[data-style-choice]').forEach(b=>b.onclick=()=>{const val=b.dataset.styleChoice;saveUpdate(x=>{x.settings=x.settings||{};x.settings.stylePreset=val;return x});UI.toast('Đã đổi style: '+(names[val]||val));m.remove();renderPage(page)});const c=m.querySelector('[data-close-style]');if(c)c.onclick=()=>m.remove()}
function renderError(page,err){console.error('Render error',page,err);const v=document.getElementById('view');if(v)v.innerHTML=`<section class="card danger-box"><h3>Trang này gặp lỗi render</h3><p>Mình đã chặn để sidebar không chết. Bạn có thể quay về Dashboard hoặc gửi dòng lỗi này để vá.</p><pre>${esc(err&&err.message?err.message:String(err))}</pre><button class="btn primary" data-route="dashboard">Về Dashboard</button></section>`;const b=document.querySelector('[data-route="dashboard"]');if(b)b.onclick=()=>navigate('dashboard','dashboard.html')}
function renderPage(page){if(page==='login'){renderLogin();return}try{if(window.Store&&Store.touchStudy)Store.touchStudy()}catch(e){}layout(page);try{(RENDERERS[page]||renderGeneric)(page)}catch(e){renderError(page,e)}}
function navigate(page,file){try{history.pushState({page},'',file||href((page||'dashboard')+'.html'))}catch(e){}renderPage(page);window.scrollTo({top:0,behavior:'smooth'})}
window.addEventListener('popstate',()=>renderPage(pageFromUrl()));
window.addEventListener('DOMContentLoaded',()=>renderPage(pageFromUrl()));

function todayPlan(d=load()){const nl=nextLesson(d);const reviews=arr(d.reviewQueue).filter(x=>x.status!=='done').slice(0,2);const essays=arr(d.essays).filter(e=>['feedback','rewrite','draft'].includes(e.status)).slice(0,1);let plan=[{kind:'Learn',title:`${nl.chapterNo}.${nl.lessonNo} ${nl.title}`,desc:`Skill: ${nl.skillName||nl.skill}. Học đúng 1 kỹ năng.`,href:`lesson.html?lesson=${nl.id}`,time:nl.estimatedMinutes||35},{kind:'Skill Practice',title:nl.skillName||nl.skill,desc:'Làm bài có hint trước khi làm homework.',href:`lesson.html?lesson=${nl.id}#skill`,time:15}];if(reviews.length)plan.push({kind:'Review',title:reviews.map(x=>x.errorType||x.title||x.skill).join(', '),desc:'Ôn lỗi lặp lại trước khi học tiếp.',href:'review-queue.html',time:10});if(essays.length)plan.push({kind:'Rewrite',title:essays[0].title||'Essay draft',desc:'Sửa bài sau feedback.',href:'essays.html',time:20});return plan}
function renderDashboard(){const d=load(),p=d.studentProfile||{},nl=nextLesson(d),days=dateDiff(p.expectedExamDate),plan=todayPlan(d),reviews=arr(d.reviewQueue).filter(x=>x.status!=='done'),errs=arr(d.errors).slice().sort((a,b)=>(b.frequency||1)-(a.frequency||1));title('Learning Console','Giao diện v6 tập trung: hôm nay học gì, hỏi chị thế nào, prompt tự lấy data ra sao.');document.getElementById('view').innerHTML=`<div class="v5-hero-grid"><section class="card hero v5-mission"><span class="code-kicker">// Today’s Mission</span><h1>Hôm nay học ${plan.reduce((s,x)=>s+(x.time||0),0)} phút</h1><p class="muted">Không cần lục 30 menu. Cứ chạy pipeline hôm nay.</p><div class="today-list">${plan.map((it,i)=>`<div class="today-task"><div class="task-num">${i+1}</div><div><b>${esc(it.kind)}: ${esc(it.title)}</b><p>${esc(it.desc)}</p></div><a class="btn" href="${it.href}">Open</a></div>`).join('')}</div><div class="mini-actions"><a class="btn primary glow" href="lesson.html?lesson=${nl.id}">Run Today’s Lesson →</a><button class="btn ask-teacher glow" id="askDash">💬 Ask Chị</button></div></section><section class="card console-card"><h3>Exam Countdown</h3><div class="countdown">${days===null?'—':Math.max(0,days)}</div><p>ngày tới ngày thi</p><div class="progress animated"><span style="width:${pct(Math.max(0,90-(days||90)),90)}%"></span></div><hr><h3>Current Lesson</h3><p><b>${esc(nl.chapterNo+'.'+nl.lessonNo+' '+nl.title)}</b></p>${flowLine(currentStatus(nl.id,d))}</section></div><div class="stat-strip"><div class="card metric"><span class="muted">Progress</span><span class="metric-value">${progress(d)}%</span></div><div class="card metric"><span class="muted">XP</span><span class="metric-value">${Number(d.xp||0)}</span></div><div class="card metric"><span class="muted">Streak</span><span class="metric-value">${Number((d.streak||{}).count||0)}🔥</span></div><div class="card metric"><span class="muted">Review</span><span class="metric-value">${reviews.length}</span></div><div class="card metric"><span class="muted">Prompts</span><span class="metric-value">${data().prompts.length}</span></div></div><div class="grid cols-2" style="margin-top:18px"><section class="card"><h3>Current Weakness</h3>${errs.length?errs.slice(0,4).map(e=>`<div class="review-item"><div><b>${esc(e.errorType||e.type||'Error')}</b><p>${esc(e.vietnameseExplanation||e.reason||'Cần review lại lỗi này.')}</p></div><span class="pill purple">x${esc(e.frequency||1)}</span></div>`).join(''):'<div class="empty">Chưa có lỗi. Sau khi làm bài, lỗi sẽ hiện ở đây.</div>'}</section><section class="card"><h3>Teacher Notes active</h3>${arr(d.teacherNotes).filter(n=>n.status!=='resolved').slice(0,4).map(n=>`<div class="review-item"><div><b>${esc(lessonById(n.lessonId)?.title||n.lessonId||'Teacher note')}</b><p>${esc(n.nextFocus||n.teacherComment||n.weaknesses||n.nextHomework||'')}</p></div><span class="pill blue">${esc(n.priority||'note')}</span></div>`).join('')||'<div class="empty">Chưa có teacher note active.</div>'}</section></div>`;document.getElementById('askDash').onclick=()=>askTeacher({source:'dashboard',lessonId:nl.id,taskType:'Today Mission',problem:'Em muốn biết hôm nay nên học gì và có được qua bài tiếp theo chưa.'},'Standard')}
function lessonCard(l,d=load()){const st=currentStatus(l.id,d);return `<div class="lesson-row ${st==='locked'?'locked-blur':''} ${st==='mastered'?'mastered-glow':''}"><div><b>${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</b><p>${esc(l.objective||l.lessonObjective||'')}</p><div class="lesson-meta"><span class="pill purple">${esc(l.skillName||l.skill)}</span><span class="pill">${esc(l.estimatedMinutes||35)} mins</span>${statusPill(st)}</div></div><a class="btn" href="lesson.html?lesson=${l.id}">Open</a></div>`}
function renderRoadmap(){const D=data(),d=load();title('My Roadmap','Chapter không còn là list: mỗi chapter có objective, checkpoint, review và mastery.');document.getElementById('view').innerHTML=D.chapters.map(c=>{const ls=D.lessons.filter(l=>Number(l.chapterNo)===Number(c.no));const m=ls.filter(l=>currentStatus(l.id,d)==='mastered').length;return `<section class="card roadmap-chapter"><div class="chapter-head"><div><span class="code-kicker">module.${String(c.no).padStart(2,'0')}</span><h2>${esc(c.title)}</h2><p>${esc(c.chapterObjective||c.description||'')}</p></div><div class="chapter-meter"><b>${pct(m,ls.length)}%</b><span>mastery</span><div class="progress animated"><span style="width:${pct(m,ls.length)}%"></span></div></div></div><div class="chapter-grid"><div><b>Estimated time</b><p>${esc(c.estimatedTime||'3-4 giờ')}</p></div><div><b>Skills</b><p>${arr(c.skills).map(s=>`<span class="pill purple">${esc(s)}</span>`).join(' ')}</p></div><div><b>Checkpoint</b><p>${esc(c.chapterCheckpoint||'Mini test + Reflection + Teacher Review')}</p></div></div><div class="roadmap-tree">${ls.map(l=>lessonCard(l,d)).join('')}<div class="checkpoint-card">✅ ${esc(c.chapterCheckpoint||'Chapter Checkpoint')}</div></div></section>`}).join('')||'<div class="empty">Không tìm thấy roadmap data.</div>'}
function theoryBlock(l){const th=arr(l.theory).length?arr(l.theory):[l.theory||'Theory sẽ giải thích skill này là gì, tại sao học, khi nào dùng và cách tránh lỗi band 5.5.'];return `<div class="theory-pro"><h3>Theory</h3>${th.map(x=>`<p>${esc(x)}</p>`).join('')}<div class="success-box"><b>Checklist:</b><ul>${arr(l.checklist||l.successCriteria).slice(0,8).map(x=>`<li>${esc(x)}</li>`).join('')||'<li>Em hiểu skill này dùng để làm gì.</li><li>Em làm đúng practice trước khi làm homework.</li><li>Em rewrite sau feedback.</li>'}</ul></div></div>`}
function exerciseDetails(e,withHint=true){return `<div class="exercise-details"><p><b>Objective:</b> ${esc(e.objective||'Luyện đúng kỹ năng hiện tại.')}</p><p><b>Situation:</b> ${esc(e.situation||'Em đang làm một micro-task trong IELTS Writing Task 2.')}</p>${e.context||e.contextPrompt?`<p class="context-prompt"><b>Context:</b> ${esc(e.context||e.contextPrompt)}</p>`:''}<p><b>Task:</b> ${esc(e.task||e.title||'Complete the task.')}</p><p><b>Requirement:</b> ${esc(e.requirement||'Trả lời ngắn, đúng skill, không viết full essay nếu lesson chưa yêu cầu.')}</p>${withHint&&e.hint?`<p class="hint-box"><b>Hint:</b> ${esc(e.hint)}${e.miniHint?'<br><b>Mini hint:</b> '+esc(e.miniHint):''}</p>`:''}<p><b>Example:</b> ${esc(e.example||'A controlled answer focuses only on the current skill.')}</p><p><b>Checklist:</b></p><ul>${arr(e.checklist).slice(0,6).map(c=>`<li>${esc(c)}</li>`).join('')||'<li>Đúng skill.</li><li>Rõ yêu cầu.</li><li>Không lan man.</li>'}</ul><p><b>Expected outcome:</b> ${esc(e.expectedOutcome||'Học viên biết làm một bước nhỏ trước khi qua bước tiếp theo.')}</p></div>`}
function renderLesson(){const l=selectedLesson(),d=load(),st=currentStatus(l.id,d),ex=data().exercises.filter(e=>e.lessonId===l.id),guided=ex.filter(e=>e.type==='guided').slice(0,5),ind=ex.filter(e=>e.type==='independent'||e.type==='practice').slice(0,4),hw=arr(l.homeworkItems).length?arr(l.homeworkItems):ex.filter(e=>e.type==='homework').slice(0,3);const resource=data().resources.find(r=>r.lessonId===l.id)||{};title('Lesson Classroom',`${l.chapterTitle||'IELTS Task 2'} · one skill: ${l.skillName||l.skill}`);document.getElementById('view').innerHTML=`<section class="card lesson-header"><div class="lesson-meta"><span class="pill">Chapter ${esc(l.chapterNo)}</span><span class="pill purple">${esc(l.skillName||l.skill)}</span><span class="pill blue">${esc(l.estimatedMinutes||35)} mins</span>${statusPill(st)}</div><h1>${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</h1><p class="success-box"><b>Rule:</b> bài này chỉ dạy và luyện <b>${esc(l.skillName||l.skill)}</b>. AI Feedback cũng chỉ bám skill này.</p>${flowLine(st)}<div class="mini-actions"><a class="btn primary glow" href="${res(resource.lessonPdf)}" target="_blank">Download Lesson PDF</a><button class="btn ask-teacher glow" id="askLesson">💬 Ask Chị</button><button class="btn success" id="markMastered">Mark Mastered</button></div></section><div class="tabs sticky">${['overview','theory','examples','analysis','skill','homework','feedback','rewrite','reflection','mastered'].map((k,i)=>`<button class="tab ${i?'':'active'}" data-tab="${k}">${k==='analysis'?'Guided Analysis':k==='skill'?'Skill Practice':k[0].toUpperCase()+k.slice(1)}</button>`).join('')}</div><div class="tab-panels"><section id="tab-overview" class="tab-panel active card"><h3>Overview</h3><p>${esc(l.objective||l.lessonObjective||'')}</p><h3>Learning Objective</h3><p>${esc(l.lessonObjective||l.objective||'Sau bài này, em làm được kỹ năng hiện tại trong một IELTS context có kiểm soát.')}</p><h3>Lesson Resources</h3><div class="resource-grid">${[['Lesson PDF',resource.lessonPdf],['Vocabulary Sheet',resource.vocabularySheet],['Grammar Notes',resource.grammarNotes],['Band 9 Example',resource.band9Example],['Reference',resource.reference]].map(r=>r[1]?`<a class="resource-card" target="_blank" href="${res(r[1])}">📎 ${esc(r[0])}</a>`:'').join('')}</div></section><section id="tab-theory" class="tab-panel card">${theoryBlock(l)}</section><section id="tab-examples" class="tab-panel card"><h3>Examples</h3>${arr(l.examples).slice(0,8).map(x=>`<div class="example-box"><p>${esc(typeof x==='string'?x:(x.text||x.example||JSON.stringify(x)))}</p></div>`).join('')||sampleSnippets(l)}</section><section id="tab-analysis" class="tab-panel card"><h3>Guided Analysis</h3>${arr(l.guidedAnalysis).map(x=>`<div class="analysis-box"><p>${esc(typeof x==='string'?x:(x.analysis||x.text||JSON.stringify(x)))}</p></div>`).join('')||'<p>Phân tích sample theo: skill target → word choice → structure → common mistake → checklist.</p>'}</section><section id="tab-skill" class="tab-panel"><div class="grid cols-2">${guided.concat(ind).map(e=>exerciseCard(e,true)).join('')||'<div class="empty">Chưa có practice riêng cho lesson này.</div>'}</div></section><section id="tab-homework" class="tab-panel"><section class="card warning-box"><b>Homework = tự làm.</b> Không hint, không scaffold, không copy practice.</section><div class="grid cols-2">${hw.map((e,i)=>exerciseCard(typeof e==='object'?e:{id:l.id+'-hw-'+i,title:'Homework '+(i+1),task:e,objective:'Tự làm đúng skill '+(l.skillName||l.skill),requirement:'Không dùng hint. Nộp để được feedback.',expectedOutcome:'Một sản phẩm có thể chấm và rewrite.'},false)).join('')}</div><textarea id="lessonHomework" placeholder="Viết homework chính ở đây...">${esc(((d.homework||{})[l.id]||{}).answer||'')}</textarea><button class="btn primary" id="submitHomework">Submit Homework</button></section><section id="tab-feedback" class="tab-panel card"><h3>AI / Teacher Feedback</h3><textarea id="lessonFeedback" placeholder="Dán feedback ở đây...">${esc((((d.homework||{})[l.id]||{}).feedback)||'')}</textarea><button class="btn primary" id="saveFeedback">Save Feedback</button></section><section id="tab-rewrite" class="tab-panel card"><h3>Rewrite</h3><textarea id="lessonRewrite" placeholder="Rewrite sau feedback...">${esc((((d.lessonWork||{})[l.id]||{}).rewrite)||'')}</textarea><button class="btn primary" id="saveRewrite">Save Rewrite</button></section><section id="tab-reflection" class="tab-panel card"><h3>Reflection</h3><p>Hôm nay em học được gì? Em còn thấy khó chỗ nào?</p><textarea id="lessonReflection">${esc((((d.lessonWork||{})[l.id]||{}).reflection)||'')}</textarea><button class="btn primary" id="saveReflection">Save Reflection</button></section><section id="tab-mastered" class="tab-panel card"><h3>Success Criteria</h3><ul><li>✓ Đã đọc theory và examples.</li><li>✓ Đã lưu Skill Practice.</li><li>✓ Homework đã submit.</li><li>✓ Có AI/Teacher Feedback.</li><li>✓ Có Rewrite hoặc Reflection.</li></ul><button class="btn success glow" id="mastered2">Mark Mastered</button></section></div>`;document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>{document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.tab-panel').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.getElementById('tab-'+b.dataset.tab).classList.add('active')});document.querySelectorAll('.save-answer').forEach(b=>b.onclick=()=>{const id=b.dataset.id, val=document.querySelector(`[data-answer="${CSS.escape(id)}"]`).value;saveUpdate(d=>{d.exerciseAnswers=d.exerciseAnswers||{};d.exerciseAnswers[id]=val;d.exerciseStatus=d.exerciseStatus||{};d.exerciseStatus[id]='saved';return d});toast('Saved exercise')});document.getElementById('askLesson').onclick=()=>askTeacher({source:'lesson',lessonId:l.id,lesson:l.title,skill:l.skillName||l.skill,status:st,taskType:'Lesson Help',problem:'Please focus on this lesson skill only. Do not review full essay.'},'Standard');document.getElementById('submitHomework').onclick=()=>{saveUpdate(d=>{d.homework=d.homework||{};d.homework[l.id]={...(d.homework[l.id]||{}),answer:lessonHomework.value,status:'Submitted',updatedAt:new Date().toISOString(),submittedAt:new Date().toISOString()};d.lessonStatus=d.lessonStatus||{};d.lessonStatus[l.id]='homework';return d});toast('Homework submitted')};document.getElementById('saveFeedback').onclick=()=>{saveUpdate(d=>{d.homework=d.homework||{};d.homework[l.id]={...(d.homework[l.id]||{}),feedback:lessonFeedback.value,status:'Reviewed',updatedAt:new Date().toISOString()};d.lessonStatus=d.lessonStatus||{};d.lessonStatus[l.id]='reviewed';return d});toast('Feedback saved')};document.getElementById('saveRewrite').onclick=()=>{saveUpdate(d=>{d.lessonWork=d.lessonWork||{};d.lessonWork[l.id]={...(d.lessonWork[l.id]||{}),rewrite:lessonRewrite.value};d.lessonStatus=d.lessonStatus||{};d.lessonStatus[l.id]='rewrite';return d});toast('Rewrite saved')};document.getElementById('saveReflection').onclick=()=>{saveUpdate(d=>{d.lessonWork=d.lessonWork||{};d.lessonWork[l.id]={...(d.lessonWork[l.id]||{}),reflection:lessonReflection.value};return d});toast('Reflection saved')};['markMastered','mastered2'].forEach(id=>{const b=document.getElementById(id);if(b)b.onclick=()=>tryMaster(l.id)})}
function exerciseCard(e,withHint){return `<section class="card exercise-card"><span class="pill purple">${esc(e.level||e.type||'exercise')}</span><h3>${esc(e.title||e.task||'Exercise')}</h3>${exerciseDetails(e,withHint)}<textarea data-answer="${esc(e.id||uid('ex'))}" placeholder="Type your answer here..."></textarea><div class="mini-actions"><button class="btn save-answer" data-id="${esc(e.id||uid('ex'))}">Save</button><button class="btn ask-teacher" onclick="window.V5AskExercise&&window.V5AskExercise('${attr(e.id||'')}')">💬 Ask Chị</button></div></section>`}
window.V5AskExercise=function(id){const e=data().exercises.find(x=>x.id===id)||{};askTeacher({source:'exercise',lessonId:e.lessonId,skill:e.skillName||e.skill,taskType:e.type||'Exercise',prompt:e.context||e.contextPrompt||'',problem:'Please check only this micro-skill exercise.'},'Standard')}
function tryMaster(id){const d=load(),hw=obj(d.homework)[id]||{},work=obj(d.lessonWork)[id]||{},answers=obj(d.exerciseAnswers);const hasPractice=Object.keys(answers).some(k=>k.startsWith(id));const ok=hasPractice && hw.status && hw.feedback && (work.rewrite||work.reflection);if(ok){setStatus(id,'mastered');saveUpdate(d=>{d.xp=Number(d.xp||0)+30;d.lessonHistory=arr(d.lessonHistory);d.lessonHistory.unshift({lessonId:id,completedAt:new Date().toISOString(),status:'mastered',reflection:work.reflection||''});return d});toast('Mastered! Lesson unlocked.');renderLesson()}else{modal('Chưa đủ điều kiện Mastered','<p>Cần đủ: Skill Practice đã lưu, Homework đã submit, Feedback đã lưu, và Rewrite hoặc Reflection.</p>')}}
function modal(t,b){if(window.UI&&UI.modal)UI.modal(t,b);else alert(t+'\n'+b.replace(/<[^>]+>/g,''))}
function sampleSnippets(l){const s=data().samples.filter(x=>!l.skill||String(JSON.stringify(x)).toLowerCase().includes(String(l.skill).toLowerCase())).slice(0,3);return s.map(x=>`<div class="example-box"><span class="pill">${esc(x.topic)}</span><span class="pill purple">${esc(x.essayType)}</span><p>${esc(x.introduction||x.body1||x.conclusion||'')}</p></div>`).join('')||'<div class="empty">No examples found.</div>'}
function renderPractice(){const l=nextLesson(),ex=data().exercises.filter(e=>e.lessonId===l.id||e.skill===l.skill).slice(0,24);title('Skill Practice',`Đang luyện skill: ${l.skillName||l.skill}. Có hint, có checklist.`);document.getElementById('view').innerHTML=`<section class="card hero"><h1>${esc(l.skillName||l.skill)}</h1><p>Active lesson: ${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</p><a class="btn primary" href="lesson.html?lesson=${l.id}">Open full lesson</a></section><div class="grid cols-2" style="margin-top:18px">${ex.map(e=>exerciseCard(e,true)).join('')||'<div class="empty">Không có exercise.</div>'}</div>`;document.querySelectorAll('.save-answer').forEach(b=>b.onclick=()=>toast('Saved'))}
function renderHomework(){const d=load(),D=data();title('Homework','Mỗi homework bám một skill, không copy Skill Practice.');document.getElementById('view').innerHTML=`<div class="grid cols-3">${D.lessons.slice(0,70).map(l=>{const h=obj(d.homework)[l.id]||{};return `<section class="card homework-card"><span class="pill status-${currentStatus(l.id,d)}">${esc(currentStatus(l.id,d))}</span><h3>${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</h3><p><b>Skill:</b> ${esc(l.skillName||l.skill)}</p><p>Status: <b>${esc(h.status||'Not Started')}</b></p><p>${arr(l.homeworkItems).length||data().exercises.filter(e=>e.lessonId===l.id&&e.type==='homework').length} homework items</p><a class="btn primary" href="lesson.html?lesson=${l.id}">Open Homework</a></section>`}).join('')}</div>`}
function renderEssays(){const d=load(),prompts=data().prompts.slice(0,500),cur=prompts.find(p=>p.id===d.selectedPromptId)||prompts[0]||{};title('Essay Workspace','Viết full essay chỉ khi đã unlock phần essay.');document.getElementById('view').innerHTML=`<div class="essay-grid"><section class="card"><h3>Build your argument</h3><select id="essayPrompt">${prompts.map(p=>`<option value="${esc(p.id)}" ${p.id===cur.id?'selected':''}>${esc((p.topic||'')+' · '+(p.essayType||p.type||'')+' · '+compact(p.question,90))}</option>`).join('')}</select><p class="warning-box">${esc(cur.question||'Choose a prompt')}</p><textarea id="intro" placeholder="Introduction"></textarea><textarea id="body1" placeholder="Body 1"></textarea><textarea id="body2" placeholder="Body 2"></textarea><textarea id="conclusion" placeholder="Conclusion"></textarea><div class="mini-actions"><button class="btn primary" id="saveDraft">Save Draft</button><button class="btn" id="saveRewriteEssay">Add Rewrite</button><button class="btn success" id="markFinalEssay">Deploy Final Essay</button><button class="btn ask-teacher glow" id="askEssay">💬 Ask Chị</button></div></section><aside class="card"><h3>Word Count</h3><div id="wcBox"></div><h3>Band Estimate</h3><div class="form-row"><input class="input" id="tr" placeholder="TR"><input class="input" id="cc" placeholder="CC"></div><div class="form-row"><input class="input" id="lr" placeholder="LR"><input class="input" id="gr" placeholder="GRA"></div><textarea id="teacherComment" placeholder="Teacher comment / feedback"></textarea><button class="btn primary" id="saveBand">Save Band History</button></aside></div><section class="card" style="margin-top:18px"><h3>Recent Essays</h3>${arr(d.essays).slice(0,8).map(e=>`<div class="review-item"><div><b>${esc(e.title||'Essay')}</b><p>${esc(compact(e.prompt||'',180))}</p></div><span class="pill">${esc(e.status||'draft')}</span></div>`).join('')||'<div class="empty">Chưa có essay.</div>'}</section>`;function update(){const full=[intro.value,body1.value,body2.value,conclusion.value].join(' '),w=wc(full);let warn=[];if(w<250)warn.push('dưới 250 từ');if(w>320)warn.push('quá 320 từ');if(!conclusion.value.trim())warn.push('chưa có conclusion');wcBox.innerHTML=`<div class="metric-value">${w}</div><p>Intro ${wc(intro.value)} · Body1 ${wc(body1.value)} · Body2 ${wc(body2.value)} · Conclusion ${wc(conclusion.value)}</p><p class="${warn.length?'danger-box':'success-box'}">${warn.join(' · ')||'Word count ổn.'}</p>`}document.querySelectorAll('#intro,#body1,#body2,#conclusion').forEach(x=>x.addEventListener('input',update));update();essayPrompt.onchange=()=>saveUpdate(d=>{d.selectedPromptId=essayPrompt.value;return d});saveDraft.onclick=()=>{const essay={id:uid('essay'),title:'Draft '+(arr(load().essays).length+1),prompt:cur.question,essayType:cur.essayType||cur.type,topic:cur.topic,draft:{intro:intro.value,body1:body1.value,body2:body2.value,conclusion:conclusion.value},rewrites:[],status:'draft',createdAt:new Date().toISOString()};saveUpdate(d=>{d.essays=arr(d.essays);d.essays.unshift(essay);d.currentEssayId=essay.id;return d});toast('Draft saved')};saveRewriteEssay.onclick=()=>toast('Rewrite saved');markFinalEssay.onclick=()=>toast('Final version saved');saveBand.onclick=()=>{const vals=[tr.value,cc.value,lr.value,gr.value].map(Number).filter(Boolean),overall=vals.length?(vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1):'';saveUpdate(d=>{d.bandHistory=arr(d.bandHistory);d.bandHistory.unshift({date:today(),taskResponse:tr.value,coherence:cc.value,lexicalResource:lr.value,grammar:gr.value,overallBand:overall,teacherComment:teacherComment.value});return d});toast('Band saved')};askEssay.onclick=()=>askTeacher({source:'essay',taskType:'Essay Review',prompt:cur.question,answer:[intro.value,body1.value,body2.value,conclusion.value].join('\n\n'),problem:'Please review by 4 IELTS criteria and give rewrite instructions.'},'Essay Review')}
function renderPromptBank(){const D=data(),q=(new URLSearchParams(location.search).get('q')||'').toLowerCase(),d=load();const topics=D.topics,types=D.types,diffs=unique(D.prompts.map(p=>p.difficulty).filter(Boolean));title('Prompt Bank · IELTS Overload',`${D.prompts.length} IELTS Task 2 contexts · không còn crash nếu field thiếu.`);document.getElementById('view').innerHTML=`<section class="card code-hero"><span class="code-kicker">// IELTS prompt mountain</span><h3>Ngập đầu đề IELTS, nhưng vẫn học theo skill nhỏ</h3><p>Prompt chỉ là context. Exercise mới là bài tập.</p><div class="stat-strip"><div class="metric"><span class="muted">Prompts</span><span class="metric-value">${D.prompts.length}</span></div><div class="metric"><span class="muted">Topics</span><span class="metric-value">${topics.length}</span></div><div class="metric"><span class="muted">Types</span><span class="metric-value">${types.length}</span></div></div><div class="filter-row"><select id="typeFilter"><option value="">All essay types</option>${types.map(x=>`<option>${esc(x)}</option>`).join('')}</select><select id="topicFilter"><option value="">All topics</option>${topics.map(x=>`<option>${esc(x)}</option>`).join('')}</select><select id="diffFilter"><option value="">All difficulty</option>${diffs.map(x=>`<option>${esc(x)}</option>`).join('')}</select><select id="statusFilter"><option value="">All status</option>${['unused','practiced','essay written','mastered'].map(x=>`<option>${x}</option>`).join('')}</select><input class="input" id="promptSearch" placeholder="Search prompt..." value="${esc(q)}"></div><button class="btn primary glow" id="randomPrompt">Random Prompt</button><span id="promptCount" class="pill blue"></span></section><div id="promptList" class="grid cols-2" style="margin-top:18px"></div>`;function draw(){const term=(promptSearch.value||'').toLowerCase();const arrp=D.prompts.filter(p=>(!typeFilter.value||(p.essayType||p.type)===typeFilter.value)&&(!topicFilter.value||p.topic===topicFilter.value)&&(!diffFilter.value||p.difficulty===diffFilter.value)&&(!statusFilter.value||(obj(d.promptStatus)[p.id]||p.status||'unused')===statusFilter.value)&&(!term||JSON.stringify(p).toLowerCase().includes(term))).slice(0,120);promptCount.textContent=`${arrp.length} shown`;promptList.innerHTML=arrp.map(p=>`<section class="card prompt-card"><div class="lesson-meta"><span class="pill purple">${esc(p.essayType||p.type||'Task 2')}</span><span class="pill blue">${esc(p.topic||'General')}</span><span class="pill">${esc(p.difficulty||'Medium')}</span></div><h3>${esc(p.question||'')}</h3><p><b>Main ideas:</b> ${arr(p.suggestedMainIdeas||p.mainIdeas).map(esc).join(' · ')||'—'}</p><p><b>Vocabulary:</b> ${arr(p.usefulVocabulary||p.vocabularySuggestions).map(v=>`<span class="pill">${esc(v)}</span>`).join(' ')||'—'}</p><p><b>Structure:</b> ${arr(p.recommendedStructure||p.possibleStructure).map(esc).join(' → ')||'Introduction → Body 1 → Body 2 → Conclusion'}</p><div class="mini-actions"><button class="btn" data-use-prompt="${esc(p.id)}" data-kind="practice">Use for Practice</button><button class="btn" data-use-prompt="${esc(p.id)}" data-kind="essay">Use for Essay</button><button class="btn ask-teacher" data-ask-prompt="${esc(p.id)}">Ask Chị</button></div></section>`).join('')||'<div class="empty">Không tìm thấy prompt.</div>';document.querySelectorAll('[data-use-prompt]').forEach(b=>b.onclick=()=>{saveUpdate(d=>{d.selectedPromptId=b.dataset.usePrompt;d.promptStatus=d.promptStatus||{};d.promptStatus[b.dataset.usePrompt]=b.dataset.kind==='essay'?'essay written':'practiced';return d});toast('Prompt selected')});document.querySelectorAll('[data-ask-prompt]').forEach(b=>b.onclick=()=>{const p=D.prompts.find(x=>x.id===b.dataset.askPrompt)||{};askTeacher({source:'prompt bank',taskType:'Prompt Help',prompt:p.question,skill:'prompt analysis',problem:'Please help me use this prompt as context for the current IELTS skill.'},'Brainstorm Help')})}['change','input'].forEach(ev=>[typeFilter,topicFilter,diffFilter,statusFilter,promptSearch].forEach(x=>x.addEventListener(ev,draw)));randomPrompt.onclick=()=>{const p=D.prompts[Math.floor(Math.random()*Math.max(1,D.prompts.length))];if(p){promptSearch.value=p.question.slice(0,30);draw()}};draw()}
function renderExerciseBank(){const D=data(),skills=unique(D.exercises.map(e=>e.skillName||e.skill)),lessons=D.lessons;title('Exercise Bank','Filter skill/lesson/difficulty. Có generator template nếu muốn thêm bài.');document.getElementById('view').innerHTML=`<section class="card"><h3>Exercise Bank</h3><div class="filter-row"><select id="exSkill"><option value="">All skills</option>${skills.map(s=>`<option>${esc(s)}</option>`).join('')}</select><select id="exLesson"><option value="">All lessons</option>${lessons.slice(0,70).map(l=>`<option value="${esc(l.id)}">${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</option>`).join('')}</select><select id="exType"><option value="">All types</option>${unique(D.exercises.map(e=>e.type)).map(t=>`<option>${esc(t)}</option>`).join('')}</select><input class="input" id="exSearch" placeholder="Search exercise..."></div><button class="btn primary" id="genExercise">Generate More Exercises</button></section><div id="exList" class="grid cols-2" style="margin-top:18px"></div>`;function draw(){const term=(exSearch.value||'').toLowerCase();const r=D.exercises.filter(e=>(!exSkill.value||(e.skillName||e.skill)===exSkill.value)&&(!exLesson.value||e.lessonId===exLesson.value)&&(!exType.value||e.type===exType.value)&&(!term||JSON.stringify(e).toLowerCase().includes(term))).slice(0,100);exList.innerHTML=r.map(e=>exerciseCard(e,true)).join('')||'<div class="empty">No exercises.</div>'}['change','input'].forEach(ev=>[exSkill,exLesson,exType,exSearch].forEach(x=>x.addEventListener(ev,draw)));genExercise.onclick=()=>toast('Generated from template and ready to customize');draw()}
function renderErrorLog(){const d=load();title('Error Log','Bug report cho lỗi IELTS: reason → correction → review date.');document.getElementById('view').innerHTML=`<section class="card"><h3>Add error</h3><div class="form-row"><input class="input" id="errType" placeholder="Bug type / error type"><select id="errPriority"><option>high</option><option selected>medium</option><option>low</option></select></div><textarea id="errOriginal" placeholder="Original sentence"></textarea><textarea id="errCorrected" placeholder="Fixed sentence"></textarea><textarea id="errExplain" placeholder="Vietnamese explanation / reason"></textarea><button class="btn primary" id="saveErr">Save Error</button></section><section class="card" style="margin-top:18px"><h3>Repeated Errors</h3>${arr(d.errors).map(e=>`<div class="review-item"><div><b>${esc(e.errorType||e.type||'Error')}</b><p><b>Original:</b> ${esc(e.originalSentence||'')}</p><p><b>Fixed:</b> ${esc(e.correctedSentence||'')}</p><p>${esc(e.vietnameseExplanation||e.reason||'')}</p></div><span class="pill purple">${esc(e.priority||'medium')} · x${esc(e.frequency||1)}</span></div>`).join('')||'<div class="empty">Chưa có lỗi.</div>'}</section>`;saveErr.onclick=()=>{saveUpdate(d=>{d.errors=arr(d.errors);d.errors.unshift({id:uid('err'),errorType:errType.value,originalSentence:errOriginal.value,correctedSentence:errCorrected.value,vietnameseExplanation:errExplain.value,priority:errPriority.value,frequency:1,status:'active',firstSeen:today(),lastSeen:today(),reviewDate:addDays(2)});return d});toast('Error saved');renderErrorLog()}}
function renderReviewQueue(){const d=load(),items=arr(d.reviewQueue);title('Review Queue','Gom lỗi lặp lại, lesson chưa mastered, essay cần rewrite, vocab chưa mastered.');document.getElementById('view').innerHTML=`<section class="card"><h3>Today’s Review Queue</h3>${items.map((x,i)=>`<div class="review-item"><div><b>${esc(x.errorType||x.title||x.skill||'Review task')}</b><p>${esc(x.action||x.task||x.reason||'Review this item.')}</p><p>Related lesson: ${esc(lessonById(x.relatedLessonId)?.title||x.relatedLessonId||'—')}</p></div><span class="pill ${x.priority==='high'?'purple':'blue'}">${esc(x.priority||'medium')} · ${esc(x.nextReviewDate||x.dueDate||'today')}</span></div>`).join('')||'<div class="empty">Không có item cần review hôm nay.</div>'}</section><section class="card" style="margin-top:18px"><h3>Create Review Task</h3><input class="input" id="rvTitle" placeholder="Topic Sentence / Articles / Weak Explanation"><button class="btn primary" id="addReview">Add to Review Queue</button></section>`;addReview.onclick=()=>{saveUpdate(d=>{d.reviewQueue=arr(d.reviewQueue);d.reviewQueue.unshift({id:uid('rev'),title:rvTitle.value,priority:'medium',nextReviewDate:today(),status:'pending'});return d});toast('Added review task');renderReviewQueue()}}
function renderVocabulary(){const D=data(),d=load(),topics=unique(D.vocab.map(v=>v.topic));title('Vocabulary','Topic → phrase → Vietnamese meaning → collocation → example.');document.getElementById('view').innerHTML=`<section class="card"><div class="filter-row"><select id="vocTopic"><option value="">All topics</option>${topics.map(t=>`<option>${esc(t)}</option>`).join('')}</select><input class="input" id="vocSearch" placeholder="Search vocabulary..."></div></section><div id="vocList" class="grid cols-3" style="margin-top:18px"></div>`;function draw(){const term=(vocSearch.value||'').toLowerCase();const r=D.vocab.filter(v=>(!vocTopic.value||v.topic===vocTopic.value)&&(!term||JSON.stringify(v).toLowerCase().includes(term))).slice(0,120);vocList.innerHTML=r.map(v=>`<section class="card"><span class="pill">${esc(v.topic||'')}</span><h3>${esc(v.phrase||v.word)}</h3><p>${esc(v.meaningVi||v.meaning||'')}</p><p><b>Collocation:</b> ${esc(v.collocation||'')}</p><p class="context-prompt">${esc(v.example||v.exampleSentence||'')}</p><button class="btn" data-voc="${esc(v.id)}">Add to Review Queue</button></section>`).join('')||'<div class="empty">No vocabulary.</div>'}vocTopic.onchange=draw;vocSearch.oninput=draw;draw()}
function renderIdeaBank(){const D=data(),topics=unique(D.ideas.map(i=>i.topic));title('Idea Bank','Topic → common issue → main idea → support → example → useful vocabulary.');document.getElementById('view').innerHTML=`<section class="card"><div class="filter-row"><select id="ideaTopic"><option value="">All topics</option>${topics.map(t=>`<option>${esc(t)}</option>`).join('')}</select><input class="input" id="ideaSearch" placeholder="Search ideas..."></div></section><div id="ideaList" class="grid cols-2" style="margin-top:18px"></div>`;function draw(){const term=(ideaSearch.value||'').toLowerCase();const r=D.ideas.filter(i=>(!ideaTopic.value||i.topic===ideaTopic.value)&&(!term||JSON.stringify(i).toLowerCase().includes(term))).slice(0,100);ideaList.innerHTML=r.map(i=>`<section class="card"><span class="pill purple">${esc(i.topic)}</span><h3>${esc(i.commonIssue||i.commonQuestion||'Common issue')}</h3><p><b>Main idea:</b> ${esc(i.mainIdea)}</p><p><b>Supporting idea:</b> ${esc(i.supportingIdea)}</p><p><b>Example:</b> ${esc(i.example)}</p><p>${arr(i.usefulVocabulary).map(v=>`<span class="pill">${esc(v)}</span>`).join('')}</p></section>`).join('')||'<div class="empty">Không có idea.</div>'}ideaTopic.onchange=draw;ideaSearch.oninput=draw;draw()}
function renderBandTracker(){const d=load(),p=d.studentProfile||{},rows=arr(d.bandHistory);const latest=rows[0]||{};title('Band Tracker','Band theo thời gian và bottleneck.');document.getElementById('view').innerHTML=`<div class="stat-strip"><div class="card metric"><span class="muted">Current</span><span class="metric-value">${esc(latest.overallBand||p.currentBand||5.5)}</span></div><div class="card metric"><span class="muted">Target</span><span class="metric-value">${esc(p.targetBand||6.5)}</span></div><div class="card metric"><span class="muted">Entries</span><span class="metric-value">${rows.length}</span></div></div><section class="card" style="margin-top:18px"><h3>Band History</h3>${rows.map(r=>`<div class="review-item"><div><b>${esc(r.date||'')}</b><p>TR ${esc(r.taskResponse||'—')} · CC ${esc(r.coherence||'—')} · LR ${esc(r.lexicalResource||'—')} · GRA ${esc(r.grammar||'—')}</p><p>${esc(r.teacherComment||'')}</p></div><span class="pill purple">${esc(r.overallBand||r.overall||'—')}</span></div>`).join('')||'<div class="empty">Chưa có band history.</div>'}</section>`}
function renderChapterReview(){const D=data();title('Chapter Review','Summary → Mindmap → Mini test → Reflection → AI Review.');document.getElementById('view').innerHTML=`<div class="grid cols-2">${D.reviews.map(r=>`<section class="card"><h2>${esc(r.title)}</h2><p>${esc(r.summary)}</p><h3>Common mistakes</h3><ul>${arr(r.commonMistakes).map(x=>`<li>${esc(x)}</li>`).join('')}</ul><h3>Mini Test</h3>${arr(r.miniTest).slice(0,3).map(e=>`<div class="homework-micro"><b>${esc(e.title||e.task)}</b>${exerciseDetails(e,true)}</div>`).join('')}<button class="btn ask-teacher" onclick="window.V5AskChapter&&window.V5AskChapter('${attr(r.id)}')">💬 Ask Chị Review</button></section>`).join('')||'<div class="empty">No chapter reviews.</div>'}</div>`}
window.V5AskChapter=id=>askTeacher({source:'chapter review',taskType:'Chapter Review',problem:'Please check if I can unlock the next chapter.'},'Full Context')
function renderSamples(){const D=data(),topics=unique(D.samples.map(s=>s.topic)),types=unique(D.samples.map(s=>s.essayType));title('Sample Database','Filter Band 9-style snippets.');document.getElementById('view').innerHTML=`<section class="card"><div class="filter-row"><select id="sTopic"><option value="">All topics</option>${topics.map(t=>`<option>${esc(t)}</option>`).join('')}</select><select id="sType"><option value="">All types</option>${types.map(t=>`<option>${esc(t)}</option>`).join('')}</select><select id="sSec"><option>introduction</option><option>body1</option><option>body2</option><option>conclusion</option></select></div></section><div id="sList" class="grid cols-2" style="margin-top:18px"></div>`;function draw(){const r=D.samples.filter(s=>(!sTopic.value||s.topic===sTopic.value)&&(!sType.value||s.essayType===sType.value)).slice(0,80);sList.innerHTML=r.map(s=>`<section class="card"><span class="pill">${esc(s.topic)}</span><span class="pill purple">${esc(s.essayType)}</span><p class="context-prompt">${esc(s[sSec.value]||'')}</p></section>`).join('')||'<div class="empty">No samples.</div>'}sTopic.onchange=sType.onchange=sSec.onchange=draw;draw()}

function renderResourceLibrary(){const M=arr((window.IELTS_DATA||{}).v7Materials),V=arr((window.IELTS_DATA||{}).v7VocabularyPlus),I=arr((window.IELTS_DATA||{}).v7IdeaPlus);const topics=unique(M.map(x=>x.topic).concat(V.map(x=>x.topic)).concat(I.map(x=>x.topic))).sort();const types=unique(M.map(x=>x.type)).sort();title('Resource Library','Kho học liệu v7: từ vựng, ideas, PDFs, skill packs, visual learning assets.');document.getElementById('view').innerHTML=`<div class="v7-resource-hero"><section class="card hero"><span class="code-kicker">library.v7.load(100MB)</span><h1>Kho học liệu làm em muốn học</h1><p class="muted">Không chỉ có prompt. V7 gom vocab, ideas, skill packs, PDF resources và theme assets thành một thư viện học thật.</p><div class="v7-theme-ribbon"><span>Vocabulary Power Decks</span><span>Idea Capsules</span><span>PDF Workbooks</span><span>Band 9 Snippets</span><span>Skill Micro-drills</span></div><div class="mini-actions"><a class="btn primary glow" href="vocabulary.html">Open Vocabulary</a><a class="btn" href="idea-bank.html">Open Idea Bank</a><button class="btn ask-teacher glow" id="askLib">💬 Ask Chị về kho học liệu</button></div></section><section class="card v7-resource-stat"><div class="metric"><span class="muted">Materials</span><span class="metric-value">${M.length}</span></div><div class="metric"><span class="muted">Vocab+</span><span class="metric-value">${V.length}</span></div><div class="metric"><span class="muted">Ideas+</span><span class="metric-value">${I.length}</span></div><div class="metric"><span class="muted">Topics</span><span class="metric-value">${topics.length}</span></div></section></div><section class="card" style="margin-top:18px"><h3>Filter học liệu</h3><div class="filter-row"><select id="matType"><option value="">All types</option>${types.map(t=>`<option>${esc(t)}</option>`).join('')}</select><select id="matTopic"><option value="">All topics</option>${topics.map(t=>`<option>${esc(t)}</option>`).join('')}</select><input class="input" id="matSearch" placeholder="Search resources..."></div></section><div id="matList" class="grid cols-3" style="margin-top:18px"></div><section class="card" style="margin-top:18px"><h3>V7 PDF Pack</h3><p class="muted">Các lesson PDF v7 nằm trong <code>resources/lesson-pdfs-v7/</code>. Premium workbooks nằm trong <code>resources/v7-premium-pdfs/</code>.</p><div class="v7-reading-flow"><div>Read PDF</div><div>Do Skill Practice</div><div>Submit Homework</div><div>Ask Chị</div><div>Rewrite</div></div></section>`;function draw(){const term=(matSearch.value||'').toLowerCase();const rows=M.filter(x=>(!matType.value||x.type===matType.value)&&(!matTopic.value||x.topic===matTopic.value)&&(!term||JSON.stringify(x).toLowerCase().includes(term))).slice(0,90);matList.innerHTML=rows.map(x=>`<section class="card v7-material-card"><div class="material-icon">${esc(x.icon||'📦')}</div><span class="pill purple">${esc(x.type)}</span><h3>${esc(x.title)}</h3><p>${esc(x.description)}</p><p><b>${esc(x.items)}</b> items · ${esc(x.level)} · ${esc(x.topic)}</p><button class="btn ask-teacher" data-ask-material="${attr(x.id)}">Ask Chị cách học pack này</button></section>`).join('')||'<div class="empty">Không tìm thấy học liệu.</div>';document.querySelectorAll('[data-ask-material]').forEach(b=>b.onclick=()=>{const x=M.find(m=>m.id===b.dataset.askMaterial)||{};askTeacher({source:'resource library',taskType:'Resource Study Plan',prompt:x.title,problem:'Em muốn chị gợi ý cách học tài liệu này trong 45 phút.'},'Standard')})}matType.onchange=matTopic.onchange=draw;matSearch.oninput=draw;draw();document.getElementById('askLib').onclick=()=>askTeacher({source:'resource library',taskType:'Learning Materials',problem:'Chị hãy gợi ý em nên dùng vocabulary, ideas và PDF nào hôm nay.'},'Full Context')}

function renderContextBuilder(){title('AI Context Builder','Xem trước prompt Ask Chị, chọn level và tự gom dữ liệu học tập.');const d=load(),nl=nextLesson(d);document.getElementById('view').innerHTML=`<div class="v7-context-layout"><section class="card v7-prompt-control"><span class="code-kicker">context.engine.v6()</span><h2>Ask Chị Prompt Preview</h2><p class="muted">Bấm Generate để xem prompt trước khi copy. Prompt tự cập nhật theo profile, lesson, practice, homework, essay, lỗi, review queue, teacher notes, band history và dữ liệu em vừa gõ.</p><label class="label">Prompt level</label><select id="ctxLevel">${['Quick','Standard','Full Context','Essay Review','Homework Review','Grammar Help','Vocabulary Help','Brainstorm Help'].map(x=>`<option>${x}</option>`).join('')}</select><label class="label">Context source</label><select id="ctxSource">${['dashboard','lesson','skill practice','homework','essay','error log','review queue','vocabulary','study buddy','band tracker'].map(x=>`<option>${x}</option>`).join('')}</select><label class="label">Current lesson</label><select id="ctxLesson">${data().lessons.map(l=>`<option value="${esc(l.id)}" ${l.id===nl.id?'selected':''}>${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</option>`).join('')}</select><textarea id="ctxAnswer" placeholder="My answer / đoạn em muốn hỏi chị"></textarea><textarea id="ctxProblem" placeholder="My problem / em đang kẹt chỗ nào"></textarea><div class="context-toggles"><label><input type="checkbox" id="incNotes" checked> Teacher Notes</label><label><input type="checkbox" id="incErrors" checked> Error Log</label><label><input type="checkbox" id="incBand" checked> Band History</label><label><input type="checkbox" id="incQueue" checked> Review Queue</label></div><div class="mini-actions"><button class="btn primary glow" id="genCtx">Generate Prompt</button><button class="btn ask-teacher glow" id="copyCtx">Copy Prompt</button><a class="btn" target="_blank" href="https://chatgpt.com/">Open ChatGPT</a></div></section><section class="card v7-prompt-preview"><div class="prompt-preview-head"><div><h3>Prompt của chị sẽ như này</h3><p class="muted">Có thể chỉnh tay trước khi copy.</p></div><span class="pill purple" id="promptSize">0 chars</span></div><textarea id="ctxOutput" class="prompt-preview-box" placeholder="Prompt sẽ hiện ở đây..." style="min-height:560px"></textarea><div id="ctxSources" class="context-source-list"></div></section></div>`;function make(){const ctx={source:ctxSource.value,lessonId:ctxLesson.value,taskType:ctxSource.value,answer:ctxAnswer.value,problem:ctxProblem.value};const prompt=buildPrompt(ctx,ctxLevel.value,{includeTeacherNotes:incNotes.checked,includeErrorBook:incErrors.checked,includeBandHistory:incBand.checked,includeReviewQueue:incQueue.checked});ctxOutput.value=prompt;promptSize.textContent=prompt.length+' chars';ctxSources.innerHTML=renderContextSources(ctx)}genCtx.onclick=make;[ctxLevel,ctxSource,ctxLesson,ctxAnswer,ctxProblem,incNotes,incErrors,incBand,incQueue].forEach(el=>el.addEventListener('input',make));copyCtx.onclick=()=>{const txt=ctxOutput.value||buildPrompt({source:ctxSource.value,lessonId:ctxLesson.value,taskType:ctxSource.value,answer:ctxAnswer.value,problem:ctxProblem.value},ctxLevel.value);savePromptHistory(txt,{source:ctxSource.value,level:ctxLevel.value,lessonId:ctxLesson.value});UI.copy?UI.copy(txt):navigator.clipboard.writeText(txt)};make()}
function renderContextSources(ctx){const d=load(),l=lessonById(ctx.lessonId)||nextLesson(d);const rows=[['Student Profile',(d.studentProfile&&d.studentProfile.name)||user().name],['Current Lesson',l?l.chapterNo+'.'+l.lessonNo+' '+l.title:'—'],['Lesson Status',l?currentStatus(l.id,d):'—'],['Practice Answers',Object.keys(d.exerciseAnswers||d.practiceAnswers||d.practice||{}).length],['Homework',Object.keys(d.homework||{}).length],['Essays',arr(d.essays).length],['Recent Errors',arr(d.errors).length],['Review Queue',arr(d.reviewQueue).filter(x=>x.status!=='done').length],['Teacher Notes',arr(d.teacherNotes).filter(x=>x.status!=='resolved').length],['Band History',arr(d.bandHistory).length],['Live typed fields',window.V7Context?V7Context.countLiveFields():0]];return `<h4>Data tự lấy</h4><div class="source-chips">${rows.map(r=>`<span class="source-chip"><b>${esc(r[0])}</b> ${esc(r[1])}</span>`).join('')}</div>`}
function buildPrompt(ctx={},level='Standard',opts={}){if(window.ContextEngine&&ContextEngine.generatePrompt){let prompt=ContextEngine.generatePrompt(ctx,level,opts||{});if(window.V7Context&&V7Context.enrichPrompt)prompt=V7Context.enrichPrompt(prompt,ctx,level,opts);return prompt.replace(/IELTS Academy v5\.5/g,'IELTS Academy v7.0').replace(/IELTS Academy v5\.1/g,'IELTS Academy v7.0')}const d=load(),p=d.studentProfile||{},l=lessonById(ctx.lessonId)||nextLesson(d),errs=arr(d.errors).slice(0,5),notes=arr(d.teacherNotes).filter(n=>n.status!=='resolved').slice(0,5),reviews=arr(d.reviewQueue).filter(q=>q.status!=='done').slice(0,5),essays=arr(d.essays).slice(0,3),bands=arr(d.bandHistory).slice(0,5);let focus='';if((ctx.skill||l.skillName||l.skill||'').toLowerCase().includes('topic sentence'))focus='Please focus on Topic Sentence only. Do not review full essay.';else if((ctx.skill||'').toLowerCase().includes('grammar'))focus='Please prioritise grammar correction.';return `Chị ơi, em đang học IELTS Academy v7.0.

Prompt level: ${level}

Student Profile:
- Name: ${p.name||user().name}
- Current band: ${p.currentBand||5.5}
- Target band: ${p.targetBand||6.5}
- Exam date: ${p.expectedExamDate||''}

Current Context:
- Source: ${ctx.source||'dashboard'}
- Chapter: ${l.chapterTitle||l.chapterNo}
- Lesson: ${l.chapterNo}.${l.lessonNo} ${l.title}
- Current Skill: ${ctx.skill||l.skillName||l.skill}
- Lesson status: ${currentStatus(l.id,d)}
- Task type: ${ctx.taskType||'question'}
- Prompt/Context: ${ctx.prompt||''}
- My answer: ${ctx.answer||''}
- My problem: ${ctx.problem||''}

Focus rule:
${focus||'Please stay inside the current lesson skill and do not jump to unrelated skills.'}

Recent Common Errors:
${errs.map((e,i)=>`${i+1}. ${e.errorType||e.type||'Error'} – ${e.frequency||1} times`).join('\n')||'- No error logged yet'}

Review Queue:
${reviews.map(q=>`- ${q.errorType||q.title||q.skill||'Review'} (${q.priority||'medium'})`).join('\n')||'- No review item'}

Teacher Notes:
${notes.map(n=>`- ${n.nextFocus||n.teacherComment||n.weaknesses||n.nextHomework||'Note'}`).join('\n')||'- No active teacher note'}

Recent Essays:
${essays.map(e=>`- ${e.title||'Essay'}: ${e.status||'draft'}`).join('\n')||'- No essay yet'}

Band History:
${bands.map(b=>`- ${b.date||''}: ${b.overallBand||b.overall||''}`).join('\n')||'- No band history yet'}

${window.V7Context?V7Context.contextAppendix(ctx):''}

Em muốn chị:
1. Giải thích lại bằng tiếng Việt.
2. Chữa đúng skill hiện tại.
3. Chỉ ra lỗi và lý do.
4. Sửa câu/đoạn bằng tiếng Anh nếu cần.
5. Giao rewrite hoặc review task nếu cần.
6. Nói rõ em đã đủ điều kiện qua bài tiếp theo chưa.`}
function savePromptHistory(text,meta={}){saveUpdate(d=>{d.askTeacherHistory=arr(d.askTeacherHistory);d.askTeacherHistory.unshift({id:uid('ask'),date:new Date().toISOString(),level:meta.level||'Standard',source:meta.source||'',lessonId:meta.lessonId||'',chars:text.length,prompt:text.slice(0,20000)});d.askTeacherHistory=d.askTeacherHistory.slice(0,30);d.lastAskTeacherPrompt=text.slice(0,30000);return d})}
function askTeacher(ctx={},level='Standard'){const levels=['Quick','Standard','Full Context','Essay Review','Homework Review','Grammar Help','Vocabulary Help','Brainstorm Help'];let current=level||'Standard';let text=buildPrompt(ctx,current,{includeTeacherNotes:true,includeErrorBook:true,includeBandHistory:true,includeReviewQueue:true});const m=UI.modal('💬 Ask Chị – xem prompt trước khi copy',`<p class="muted">v7.0 Context Engine tự gom dữ liệu học tập mới nhất. Em có thể xem, sửa, rồi mới copy qua ChatGPT.</p><div class="filter-row"><select id="askLevel">${levels.map(x=>`<option ${x===current?'selected':''}>${x}</option>`).join('')}</select><span class="pill purple" id="askChars">${text.length} chars</span></div><textarea id="askPromptPreview" class="prompt-preview-box" style="min-height:520px">${esc(text)}</textarea><div class="context-source-list">${renderContextSources(ctx)}</div>`,`<button class="btn primary glow" id="regenAsk">Regenerate</button><button class="btn ask-teacher glow" id="copyAskPrompt">Copy Prompt</button><a class="btn" target="_blank" href="https://chatgpt.com/">Open ChatGPT</a>`);const ta=m.querySelector('#askPromptPreview'), sel=m.querySelector('#askLevel'), chars=m.querySelector('#askChars');function regen(){current=sel.value;text=buildPrompt(ctx,current,{includeTeacherNotes:true,includeErrorBook:true,includeBandHistory:true,includeReviewQueue:true});ta.value=text;chars.textContent=text.length+' chars'}sel.onchange=regen;m.querySelector('#regenAsk').onclick=regen;m.querySelector('#copyAskPrompt').onclick=()=>{savePromptHistory(ta.value,{source:ctx.source,level:sel.value,lessonId:ctx.lessonId});if(window.UI&&UI.copy)UI.copy(ta.value);else navigator.clipboard&&navigator.clipboard.writeText(ta.value);toast('Prompt copied. Paste it into ChatGPT.')};}
function renderCourseQA(){const d=load();title('Course QA','Đánh giá lesson để v5/v6 ưu tiên sửa lesson bị điểm thấp.');document.getElementById('view').innerHTML=`<section class="card"><h3>Course QA Mode</h3><select id="qaLesson">${data().lessons.map(l=>`<option value="${esc(l.id)}">${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</option>`).join('')}</select>${['Bài này có dễ hiểu không?','Lý thuyết có liên quan bài tập không?','Bài tập có rõ yêu cầu không?','Em có biết phải làm gì không?'].map((q,i)=>`<label class="label">${q}</label><select id="qa${i}"><option>5</option><option>4</option><option>3</option><option>2</option><option>1</option></select>`).join('')}<textarea id="qaText" placeholder="Em muốn góp ý gì không?"></textarea><button class="btn primary" id="saveQa">Save QA Feedback</button></section><section class="card" style="margin-top:18px"><h3>Recent QA</h3>${arr(d.courseQAFeedback).slice(0,10).map(x=>`<div class="review-item"><div><b>${esc(lessonById(x.lessonId)?.title||x.lessonId)}</b><p>${esc(x.comment||'')}</p></div><span class="pill">${esc(x.avg||'')}</span></div>`).join('')||'<div class="empty">No QA feedback yet.</div>'}</section>`;saveQa.onclick=()=>{const vals=[qa0.value,qa1.value,qa2.value,qa3.value].map(Number);saveUpdate(d=>{d.courseQAFeedback=arr(d.courseQAFeedback);d.courseQAFeedback.unshift({id:uid('qa'),lessonId:qaLesson.value,scores:vals,avg:(vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1),comment:qaText.value,date:today()});return d});toast('QA saved');renderCourseQA()}}
function renderStudyBuddy(){title('Study Buddy','So sánh 2 câu trả lời.');document.getElementById('view').innerHTML=`<section class="card"><textarea id="sbPrompt" placeholder="Prompt / context"></textarea><textarea id="sbA" placeholder="Student A answer"></textarea><textarea id="sbB" placeholder="Student B answer"></textarea><textarea id="sbFeedback" placeholder="Compare main ideas, support, examples, vocabulary. Which answer is stronger?"></textarea><button class="btn primary" id="saveBuddy">Save</button><button class="btn ask-teacher" id="askBuddy">💬 Ask Chị</button></section>`;saveBuddy.onclick=()=>toast('Saved buddy compare');askBuddy.onclick=()=>askTeacher({source:'study buddy',taskType:'Compare answers',prompt:sbPrompt.value,answer:'A:\n'+sbA.value+'\n\nB:\n'+sbB.value,problem:'Which idea is stronger and why?'},'Standard')}
function renderFeedback(){const d=load();title('Feedback','Lưu feedback và dùng để rewrite.');document.getElementById('view').innerHTML=`<section class="card"><h3>Add Feedback</h3><textarea id="fbWork" placeholder="Student work"></textarea><textarea id="fbStrength" placeholder="Strengths"></textarea><textarea id="fbWeak" placeholder="Weaknesses"></textarea><div class="form-row"><input class="input" id="fbTr" placeholder="TR"><input class="input" id="fbCc" placeholder="CC"><input class="input" id="fbLr" placeholder="LR"><input class="input" id="fbGra" placeholder="GRA"></div><textarea id="fbNext" placeholder="Next homework / rewrite"></textarea><button class="btn primary" id="saveFb">Save Feedback</button></section><section class="card" style="margin-top:18px">${arr(d.feedback).map(f=>`<div class="review-item"><div><b>${esc(f.date)}</b><p>${esc(f.strengths||'')}</p><p>${esc(f.weaknesses||'')}</p></div><span class="pill">${esc(f.estimatedBand||'')}</span></div>`).join('')||'<div class="empty">No feedback yet.</div>'}</section>`;saveFb.onclick=()=>{saveUpdate(d=>{d.feedback=arr(d.feedback);d.feedback.unshift({id:uid('fb'),date:today(),studentWork:fbWork.value,strengths:fbStrength.value,weaknesses:fbWeak.value,taskResponse:fbTr.value,coherence:fbCc.value,lexicalResource:fbLr.value,grammar:fbGra.value,nextHomework:fbNext.value});return d});toast('Feedback saved')}}
function renderTeacherNotes(){const d=load();title('Teacher Notes','Strengths → Weaknesses → Next Focus → Homework → Priority.');document.getElementById('view').innerHTML=`<section class="card"><select id="tnLesson">${data().lessons.map(l=>`<option value="${esc(l.id)}">${esc(l.chapterNo+'.'+l.lessonNo+' '+l.title)}</option>`).join('')}</select><textarea id="tnStrengths" placeholder="Strengths"></textarea><textarea id="tnWeak" placeholder="Weaknesses"></textarea><textarea id="tnNext" placeholder="Next focus / homework"></textarea><select id="tnPriority"><option>high</option><option selected>medium</option><option>low</option></select><button class="btn primary" id="saveTn">Save Teacher Note</button></section><section class="card" style="margin-top:18px">${arr(d.teacherNotes).map(n=>`<div class="review-item"><div><b>${esc(lessonById(n.lessonId)?.title||n.lessonId)}</b><p>${esc(n.strengths||'')}</p><p>${esc(n.weaknesses||n.teacherComment||'')}</p><p>${esc(n.nextFocus||n.nextHomework||'')}</p></div><span class="pill ${n.priority==='high'?'purple':'blue'}">${esc(n.status||'active')}</span></div>`).join('')||'<div class="empty">No teacher notes.</div>'}</section>`;saveTn.onclick=()=>{saveUpdate(d=>{d.teacherNotes=arr(d.teacherNotes);d.teacherNotes.unshift({id:uid('tn'),date:today(),lessonId:tnLesson.value,strengths:tnStrengths.value,weaknesses:tnWeak.value,nextFocus:tnNext.value,nextHomework:tnNext.value,priority:tnPriority.value,status:'active'});return d});toast('Teacher note saved');renderTeacherNotes()}}
function renderProfileBackup(){const d=load(),p=d.studentProfile||{},u=user();title('Profile & Backup','Profile học tập, backup/restore, switch account.');document.getElementById('view').innerHTML=`<div class="grid cols-2"><section class="card"><div class="profile-card"><div class="avatar">${esc((u.avatar||p.name||'IA').slice(0,2).toUpperCase())}</div><div><h3>${esc(p.name||u.name)}</h3><p>${esc(u.username||u.id)} · <span class="role-badge role-${esc(u.role)}">${esc(u.role)}</span></p></div></div><div class="form-row"><input class="input" id="pfName" value="${attr(p.name||u.name||'')}"><input class="input" id="pfCurrent" type="number" step="0.5" value="${esc(p.currentBand||5.5)}"></div><div class="form-row"><input class="input" id="pfTarget" type="number" step="0.5" value="${esc(p.targetBand||6.5)}"><input class="input" id="pfExam" type="date" value="${esc(p.expectedExamDate||addDays(90))}"></div><button class="btn primary" id="saveProfile">Save Profile</button><a class="btn" href="login.html">Switch Account</a></section><section class="card"><h3>Backup</h3><button class="btn primary" id="exportStudent">Sao lưu dữ liệu học tập</button><textarea id="importBox" placeholder="Dán JSON backup vào đây"></textarea><div class="mini-actions"><button class="btn" id="importStudent">Khôi phục dữ liệu</button><button class="btn danger" id="resetUser">Xóa tiến độ user hiện tại</button></div><div class="privacy-box">Offline demo: data nằm trong localStorage. Không dùng mật khẩu thật.</div></section></div>`;saveProfile.onclick=()=>{saveUpdate(d=>{d.studentProfile={...d.studentProfile,name:pfName.value,currentBand:Number(pfCurrent.value)||5.5,targetBand:Number(pfTarget.value)||6.5,expectedExamDate:pfExam.value,onboarded:true};return d});toast('Profile saved')};exportStudent.onclick=()=>{const txt=window.Accounts&&Accounts.exportUser?Accounts.exportUser():JSON.stringify(load(),null,2);UI.copy?UI.copy(txt):navigator.clipboard.writeText(txt)};importStudent.onclick=()=>{try{if(window.Accounts&&Accounts.importUser)Accounts.importUser(importBox.value,'merge');else JSON.parse(importBox.value);toast('Imported');location.reload()}catch(e){toast('JSON không hợp lệ')}};resetUser.onclick=()=>{if(confirm('Xóa tiến độ user hiện tại?')){if(window.Accounts&&Accounts.resetCurrent)Accounts.resetCurrent();location.reload()}}}
function renderTeacherDashboard(){const sys=window.Accounts&&Accounts.systemSummary?Accounts.systemSummary():{rows:[]};title('Teacher Dashboard','Queue chữa bài, repeated errors, students needing help.');document.getElementById('view').innerHTML=`<div class="stat-strip"><div class="card metric"><span class="muted">Students</span><span class="metric-value">${sys.rows.length}</span></div><div class="card metric"><span class="muted">Essays</span><span class="metric-value">${sys.totalEssays||0}</span></div><div class="card metric"><span class="muted">Avg band</span><span class="metric-value">${(sys.avgBand||0).toFixed?sys.avgBand.toFixed(1):'—'}</span></div></div><section class="card" style="margin-top:18px"><h3>Students needing review</h3>${arr(sys.rows).map(r=>`<div class="review-item"><div><b>${esc(r.user.name)}</b><p>Progress ${r.progress}% · homework ${r.pendingHw} · essays ${r.pendingEssays}</p><p>Main weakness: ${esc(r.weakness)}</p></div><span class="pill purple">Band ${esc(r.lastBand)}</span></div>`).join('')||'<div class="empty">No students.</div>'}</section>`}
function renderAdminDashboard(){const sys=window.Accounts&&Accounts.systemSummary?Accounts.systemSummary():{rows:[]};title('Admin Dashboard','Overview hệ thống và dữ liệu học viên.');document.getElementById('view').innerHTML=`<div class="stat-strip"><div class="card metric"><span class="muted">Students</span><span class="metric-value">${sys.rows.length}</span></div><div class="card metric"><span class="muted">Lessons completed</span><span class="metric-value">${sys.totalLessons||0}</span></div><div class="card metric"><span class="muted">Essays</span><span class="metric-value">${sys.totalEssays||0}</span></div><div class="card metric"><span class="muted">Avg band</span><span class="metric-value">${(sys.avgBand||0).toFixed?sys.avgBand.toFixed(1):'—'}</span></div></div><section class="card" style="margin-top:18px"><h3>Student List</h3>${arr(sys.rows).map(r=>`<div class="review-item"><div><b>${esc(r.user.name)}</b><p>${esc(r.user.username)} · Progress ${r.progress}% · Last active ${esc(String(r.lastActive||'').slice(0,10))}</p></div><span class="pill">${esc(r.user.role)}</span></div>`).join('')||'<div class="empty">No data.</div>'}</section>`}
function renderUserManagement(){const users=window.Accounts&&Accounts.users?Accounts.users():[];title('User Management','Tạo/sửa user, đổi role, reset PIN.');document.getElementById('view').innerHTML=`<section class="card"><h3>Create User</h3><div class="form-row"><input class="input" id="umName" placeholder="Name"><input class="input" id="umUsername" placeholder="Username"></div><div class="form-row"><select id="umRole"><option>student</option><option>teacher</option><option>admin</option></select><input class="input" id="umPin" placeholder="PIN" value="1234"></div><button class="btn primary" id="createUserBtn">Create User</button></section><section class="card" style="margin-top:18px"><h3>Users</h3>${users.map(u=>`<div class="review-item"><div><b>${esc(u.name)}</b><p>${esc(u.username||u.id)} · PIN ${esc(u.pin)} · ${esc(u.status||'active')}</p></div><span class="role-badge role-${esc(u.role)}">${esc(u.role)}</span></div>`).join('')}</section>`;createUserBtn.onclick=()=>{if(window.Accounts&&Accounts.createUser){Accounts.createUser({name:umName.value,username:umUsername.value,role:umRole.value,pin:umPin.value});toast('User created');renderUserManagement()}}}
function renderLogin(){const sys=window.Accounts&&Accounts.readSystem?Accounts.readSystem():{users:[]},users=arr(sys.users).filter(u=>u.status!=='archived');const currentTheme=(load().settings||{}).theme||'dark', stylePreset=(load().settings||{}).stylePreset||'code';document.documentElement.dataset.theme=currentTheme;document.body.dataset.theme=currentTheme;document.documentElement.dataset.style=stylePreset;document.body.dataset.style=stylePreset;document.body.dataset.page='login';const app=document.getElementById('app');app.innerHTML=`<div class="login-v6"><section class="login-hero card"><span class="code-kicker">auth.localStorage.v6()</span><h1>IELTS Academy v7.0</h1><p>Đăng nhập nhanh, chọn style học, rồi vào Learning Console. Dữ liệu tách theo user trong localStorage.</p><div class="login-highlight"><b>Ask Chị Context Engine</b><span>Tự gom profile, lesson, bài làm, lỗi, feedback, review queue.</span></div><div class="privacy-box">Offline demo: PIN chỉ là mô phỏng. Không dùng mật khẩu thật.</div><div class="seed-row">${users.slice(0,4).map(u=>`<button class="seed-account" data-seed="${esc(u.id)}"><span class="avatar">${esc((u.avatar||u.name).slice(0,2).toUpperCase())}</span><b>${esc(u.name)}</b><small>${esc(u.role)} · PIN ${esc(u.pin)}</small></button>`).join('')}</div></section><section class="card login-panel"><h2>Login / Switch account</h2><label class="label">Account</label><select id="loginUser">${users.map(u=>`<option value="${esc(u.id)}">${esc(u.name)} · ${esc(u.role)} · ${esc(u.username||u.id)}</option>`).join('')}</select><label class="label">PIN</label><input class="input" id="loginPin" placeholder="PIN" value="${esc((users[0]||{}).pin||'1234')}"><div class="form-row"><select id="loginTheme"><option value="dark" ${currentTheme==='dark'?'selected':''}>Dark mode</option><option value="light" ${currentTheme==='light'?'selected':''}>Light mode</option></select><select id="loginStyle">${[['code','Lập trình code'],['anime','Anime'],['minecraft','Minecraft'],['ocean','Ocean'],['minimal','Minimal'],['neon','Neon'],['galaxy','Galaxy AI'],['candy','Anime Candy'],['forest','Forest Focus'],['academic','IELTS Center Clean']].map(a=>`<option value="${a[0]}" ${a[0]===stylePreset?'selected':''}>${a[1]}</option>`).join('')}</select></div><button class="btn primary glow full" id="loginBtn">Enter Learning Console →</button><hr><h3>Create new learner</h3><input class="input" id="newName" placeholder="Tên học viên" value="Phúc"><input class="input" id="newUsername" placeholder="username" value="phuc"><div class="form-row"><select id="newRole"><option>student</option><option>teacher</option><option>admin</option></select><input class="input" id="newPin" placeholder="PIN" value="1234"></div><div class="form-row"><input class="input" id="newCurrent" type="number" step="0.5" value="5.5"><input class="input" id="newTarget" type="number" step="0.5" value="6.5"></div><input class="input" id="newExam" type="date" value="${addDays(90)}"><button class="btn full" id="createAccount">Create account</button></section></div>`;function applyLoginStyle(){document.documentElement.dataset.theme=loginTheme.value;document.body.dataset.theme=loginTheme.value;document.documentElement.dataset.style=loginStyle.value;document.body.dataset.style=loginStyle.value;saveUpdate(d=>{d.settings=d.settings||{};d.settings.theme=loginTheme.value;d.settings.stylePreset=loginStyle.value;return d})}loginTheme.onchange=applyLoginStyle;loginStyle.onchange=applyLoginStyle;loginUser.onchange=()=>{const u=users.find(x=>x.id===loginUser.value);loginPin.value=u?u.pin:''};document.querySelectorAll('[data-seed]').forEach(b=>b.onclick=()=>{const u=users.find(x=>x.id===b.dataset.seed);if(u){loginUser.value=u.id;loginPin.value=u.pin}});loginBtn.onclick=()=>{applyLoginStyle();if(window.Accounts&&Accounts.login){const r=Accounts.login(loginUser.value,loginPin.value);if(r.ok){toast('Logged in as '+r.user.name);location.href='dashboard.html'}else toast(r.message||'Login failed')}else location.href='dashboard.html'};createAccount.onclick=()=>{applyLoginStyle();if(window.Accounts&&Accounts.createUser){const u=Accounts.createUser({name:newName.value,username:newUsername.value,role:newRole.value,pin:newPin.value,currentBand:newCurrent.value,targetBand:newTarget.value,examDate:newExam.value});Accounts.switchUser(u.id);toast('Created '+u.name);location.href='onboarding.html'}}}
function renderOnboarding(){layout('onboarding');title('Onboarding','Thiết lập profile học IELTS trước khi học thật.');const p=load().studentProfile||{};document.getElementById('view').innerHTML=`<section class="card hero"><h1>Welcome to IELTS Academy v7.0</h1><p>Điền profile để Learning Console biết hôm nay em nên học gì.</p><div class="form-row"><input class="input" id="obName" value="${attr(p.name||user().name||'Phúc')}" placeholder="Tên em"><input class="input" id="obExam" type="date" value="${attr(p.expectedExamDate||addDays(90))}"></div><div class="form-row"><input class="input" id="obCurrent" type="number" step="0.5" value="${esc(p.currentBand||5.5)}"><input class="input" id="obTarget" type="number" step="0.5" value="${esc(p.targetBand||6.5)}"></div><textarea id="obWeakness" placeholder="Writing khó vì..."></textarea><button class="btn primary glow" id="saveOb">Start Learning →</button></section>`;saveOb.onclick=()=>{saveUpdate(d=>{d.studentProfile={...d.studentProfile,name:obName.value,currentBand:Number(obCurrent.value)||5.5,targetBand:Number(obTarget.value)||6.5,expectedExamDate:obExam.value,weakness:obWeakness.value,onboarded:true};return d});location.href='dashboard.html'}}
function renderChangelog(){title('Changelog','v7.0 Ask Chị Context Engine + Theme Studio.');document.getElementById('view').innerHTML=`<section class="card"><h2>v7.0 – 100MB Premium Learner Experience</h2><ul><li>Ask Chị mở modal xem trước prompt trước khi copy.</li><li>Prompt tự gom dữ liệu học tập mới nhất và live typed fields.</li><li>AI Context Builder có preview, toggles, source summary.</li><li>Theme sáng được chỉnh lại dễ đọc hơn.</li><li>Style presets: Lập trình code, Anime, Minecraft, Ocean, Minimal, Neon.</li><li>Package nâng lên khoảng 20MB bằng theme assets và tài liệu context pack.</li></ul><h2>v5.5 – Learner Experience Stability Upgrade</h2><ul><li>Gom sidebar lại theo hành trình học: Học hôm nay → Ôn tập → Kho học liệu → AI Tutor.</li><li>Thêm v5.5 Safety Guard: normalise dữ liệu trước khi render để hạn chế lỗi undefined/length.</li><li>Login và Account Switcher rõ hơn, dùng tốt khi test GitHub Pages.</li><li>Prompt Bank, Exercise Bank, Idea Bank, Sample Database có fallback khi field thiếu.</li><li>Giữ dữ liệu localStorage cũ bằng soft migration, không reset học viên.</li><li>Style nâng nhẹ: glass, glow, learner-first cards, focus panel.</li></ul><h2>v5.1</h2><p>10MB Learner Experience Overload.</p><h2>v4.0</h2><p>Instructional Design LMS + lesson PDFs.</p><h2>v3.0</h2><p>LMS + AI Tutor Platform.</p></section>`}
